    # Simple manual test runner when executed directly
    samples = [
        "1 + 2 * 3",
        "(1 + 2) * 3",
        "-4 + +5",
        "10 / 2",
        "10 / 0",
        "2 ** 3",
        "__import__('os').system('echo hi')",
        "True + 1",
        "3.5 - 1.2 * 2",
    ]
    for s in samples:
        print(s, "=>", evaluate_expression(s))

